__global__ void fused_matmul(float* A, float* B, float* C, int M, int N, int K) {
    int tid = threadIdx.y * 16 + threadIdx.x;
    int block_row = blockIdx.y * 64;
    int block_col = blockIdx.x * 64;
    int thread_row = threadIdx.y * 4;
    int thread_col = threadIdx.x * 4;
    __shared__ float As[1088];
    __shared__ float Bs[1040];
    float acc[16];
    for (int i = 0; i < 16; i++) {
        acc[i] = 0.0f;
    }
    float regA[4];
    float regB[4];
    for (int tile_k = 0; tile_k < K; tile_k += 16) {
        for (int li = tid; li < 1024; li += 256) {
            int a_r = li / 16;
            int a_c = li % 16;
            As[a_r * 17 + a_c] = ((block_row + a_r < M && tile_k + a_c < K) ? (A[(block_row + a_r) * K + (tile_k + a_c)]) : (0.0f));
        }
        for (int lj = tid; lj < 1024; lj += 256) {
            int b_r = lj / 64;
            int b_c = lj % 64;
            Bs[b_r * 65 + b_c] = ((tile_k + b_r < K && block_col + b_c < N) ? (B[(tile_k + b_r) * N + (block_col + b_c)]) : (0.0f));
        }
        __syncthreads();
        for (int kk = 0; kk < 16; kk++) {
            for (int m = 0; m < 4; m++) {
                regA[m] = As[(thread_row + m) * 17 + kk];
            }
            for (int n = 0; n < 4; n++) {
                regB[n] = Bs[kk * 65 + (thread_col + n)];
            }
            for (int m = 0; m < 4; m++) {
                for (int n = 0; n < 4; n++) {
                    acc[m * 4 + n] = acc[m * 4 + n] + regA[m] * regB[n];
                }
            }
        }
        __syncthreads();
    }
    for (int wm = 0; wm < 4; wm++) {
        for (int wn = 0; wn < 4; wn++) {
            if (block_row + thread_row + wm < M && block_col + thread_col + wn < N) {
                C[(block_row + thread_row + wm) * N + (block_col + thread_col + wn)] = acc[wm * 4 + wn];
            }
        }
    }
}
